@startuml
skinparam classAttributeIconSize 0

package "xxx" {
    [Shape] <<interface>> #CCCCFF{I} Shape

    note right of I : Interface\nvoid draw()

    Circle --|> void draw(): implements
    Rectangle --|> void draw(): implements  
    Square --|> void draw(): implements

    shape VoidDraw1 [[Circle]] 
    circle C_void_draw_1 as c_vd1 ""
    rectangle "[[Rectangle]]\n--\n+draw()" as r_d {}
    square S_void_draw_2 [[Square]] 

    ' Define classes properly first to avoid conflicts
    class Circle {
        +draw()
    }
    class Rectangle {
        +draw()
    }
    class Square {
        +draw()
    }

    ' Now define relationships after all elements are declared
    Circle -up-|> Shape: implement
    Rectangle -left-> Shape: implement
    Square --> Shape: implement
}

class FactoryPatternDemo {
    main(args)
}

FactoryPatternDemo -> ShapeFactory: ask for object creation via getShape method call on factory instance reference held by demo client code which uses abstract product type returned from concrete creator subclass implementing common interface defined above in package xxx containing three specific implementations namely circles rectangles squares each having their own implementation details hidden behind polymorphic behavior enabled through inheritance mechanism provided here using standard OO principles like encapsulation abstraction etcetera... 

@enduml
